//////////--------------------------------------------------------------------------------------------------------------=
always_ff@(posedge clk or negedge resetN)
begin
	if(!resetN) begin
		RGBout <=	8'h00;
		//HitEdgeCode <= 3'h0;

	end

	else begin
		RGBout <= TRANSPARENT_ENCODING ; // default  

		if (InsideRectangle == 1'b1 ) 
		begin // inside an external bracket 
			case (curr_select_shop) 
				default: RGBout <= TRANSPARENT_ENCODING;
				0:	RGBout <= TRANSPARENT_ENCODING;
				1:	RGBout <= object_colors[offsetY][offsetX];
				2:	RGBout <= object_colors[offsetY][offsetX];
				3:	RGBout <= object_colors[offsetY][offsetX];
				4: RGBout <= object_colors[OBJECT_HEIGHT_Y - 1 - offsetX][offsetY]; //clockwise
			endcase
		end  	
	end
		
end

//////////--------------------------------------------------------------------------------------------------------------=
// decide if to draw the pixel or not 
assign drawingRequest = (RGBout != TRANSPARENT_ENCODING) ? 1'b1 : 1'b0 ; // get optional transparent command from the bitmpap   
// && 
endmodule